function SheetProperties({ sheet, project, dispatch, editorDispatch, activeFloorId, u }) {
  const updateSheet = (updates) => {
    dispatch({ type: 'SHEET_UPDATE', sheet: { id: sheet.id, ...updates } });
  };

  const updateLayoutTemplate = (nextLayoutTemplate) => {
    if (nextLayoutTemplate === sheet.layoutTemplate) return;

    if (nextLayoutTemplate === 'manual') {
      dispatch({
        type: 'SHEET_UPDATE',
        sheet: materializeSheetViewportFrames(project, sheet),
      });
      return;
    }

    updateSheet({
      layoutTemplate: nextLayoutTemplate,
      viewports: (sheet.viewports || []).map((viewport) => ({
        ...viewport,
        lockAutoLayout: false,
      })),
    });
  };

  const updateTitleBlock = (updates) => {
    updateSheet({
      titleBlock: {
        ...(sheet.titleBlock || {}),
        ...updates,
      },
    });
  };

  const updateRevisions = (nextRevisions) => {
    updateSheet({ revisions: nextRevisions });
  };

  const addViewport = () => {
    try {
      const sourceFloorId = getDefaultActiveFloorId(project, activeFloorId);
      const sourceView = 'plan';
      const viewportBase = createSheetViewport(sourceView, sourceFloorId, {
        scale: 100,
        lockAutoLayout: sheet.layoutTemplate !== 'auto',
      });

      let rect;
      try {
        const source = resolveSheetViewportSource(project, viewportBase);
        rect = getDefaultViewportRect(sheet, source, viewportBase.scale, { role: viewportBase.role });
      } catch {
        // Geometry resolution failed — use default dimensions
        rect = { x: 20, y: 20, width: 160, height: 100 };
      }

      const viewport = { ...viewportBase, ...rect };
      dispatch({ type: 'SHEET_VIEWPORT_ADD', sheetId: sheet.id, viewport });
      editorDispatch({ type: 'SELECT_OBJECT', id: viewport.id, objectType: 'sheetViewport' });
      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Viewport added.' });
    } catch (err) {
      console.error('Failed to add viewport:', err);
      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Failed to add viewport.' });
    }
  };

  const addRevision = () => {
    updateRevisions([createSheetRevision(), ...(sheet.revisions || [])]);
  };

  const updateRevision = (revisionId, updates) => {
    updateRevisions((sheet.revisions || []).map((revision) => (
      revision.id === revisionId ? { ...revision, ...updates } : revision
    )));
  };

  const removeRevision = (revisionId) => {
    updateRevisions((sheet.revisions || []).filter((revision) => revision.id !== revisionId));
  };

  const paperPreset = listPaperPresets().find((preset) => preset.key === sheet.paperSize);
  const titleBlock = sheet.titleBlock || {};
  const projectTitleValue = titleBlock.projectTitleOverride || sheet.projectNameOverride;

  return (
    <div>
      <div className={styles.title}>Sheet</div>
      <InputField label="Title" value={sheet.title} onChange={(value) => updateSheet({ title: value })} />
      <InputField label="Number" value={sheet.number || ''} onChange={(value) => updateSheet({ number: value })} />
      <InputField label="Drawing" value={sheet.drawingName} onChange={(value) => updateSheet({ drawingName: value })} />
      <InputField label="Issue Date" value={sheet.issueDate || ''} onChange={(value) => updateSheet({ issueDate: value })} />
      <InputField label="Scale" value={sheet.scaleLabel} onChange={(value) => updateSheet({ scaleLabel: value })} />
      <InputField
        label="Project Title"
        value={projectTitleValue}
        onChange={(value) => updateSheet({
          projectNameOverride: value,
          titleBlock: {
            ...(sheet.titleBlock || {}),
            projectTitleOverride: value,
          },
        })}
      />
      <InputField
        label="Address"
        value={titleBlock.projectAddressOverride || ''}
        onChange={(value) => updateTitleBlock({ projectAddressOverride: value })}
      />
      <InputField
        label="Drawn By"
        value={titleBlock.drawnBy || ''}
        onChange={(value) => updateTitleBlock({ drawnBy: value })}
      />
      <InputField
        label="Checked"
        value={titleBlock.checkedBy || ''}
        onChange={(value) => updateTitleBlock({ checkedBy: value })}
      />
      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
        <label style={{ flex: '0 0 80px', fontSize: '12px', color: 'var(--color-text-secondary)' }}>Scale Mode</label>
        <select
          value={sheet.scaleMode}
          onChange={(e) => updateSheet({ scaleMode: e.target.value })}
          style={{ flex: 1, height: '28px', padding: '0 4px', border: '1px solid var(--color-border)', borderRadius: 'var(--radius-sm)', fontSize: '12px' }}
        >
          <option value="custom">Custom</option>
          <option value="per_viewport">Per viewport</option>
          <option value="as_noted">As noted</option>
        </select>
      </div>
      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
        <label style={{ flex: '0 0 80px', fontSize: '12px', color: 'var(--color-text-secondary)' }}>Layout</label>
        <select
          value={sheet.layoutTemplate}
          onChange={(e) => updateLayoutTemplate(e.target.value)}
          style={{ flex: 1, height: '28px', padding: '0 4px', border: '1px solid var(--color-border)', borderRadius: 'var(--radius-sm)', fontSize: '12px' }}
        >
          <option value="auto">Hybrid Auto</option>
          <option value="manual">Manual Frames</option>
        </select>
      </div>
      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
        <label style={{ flex: '0 0 80px', fontSize: '12px', color: 'var(--color-text-secondary)' }}>Paper</label>
        <select
          value={sheet.paperSize}
          onChange={(e) => updateSheet({ paperSize: e.target.value })}
          style={{ flex: 1, height: '28px', padding: '0 4px', border: '1px solid var(--color-border)', borderRadius: 'var(--radius-sm)', fontSize: '12px' }}
        >
          {listPaperPresets().map((preset) => (
            <option key={preset.key} value={preset.key}>{preset.label}</option>
          ))}
        </select>
      </div>
      <InputField label="Viewports" value={(sheet.viewports || []).length} readOnly />
      <button
        className={styles.actionBtn}
        onClick={addViewport}
      >
        Add viewport
      </button>
      <InputField label="Width" suffix={u.suffix} value={u.toDisplay(paperPreset?.width || 0)} readOnly />
      <InputField label="Height" suffix={u.suffix} value={u.toDisplay(paperPreset?.height || 0)} readOnly />

      <div className={styles.subtitle}>Revisions</div>
      <button className={styles.actionBtn} onClick={addRevision}>
        Add revision
      </button>
      {(sheet.revisions || []).map((revision) => (
        <div key={revision.id} className={styles.revisionCard}>
          <InputField
            label="Rev"
            value={revision.code}
            onChange={(value) => updateRevision(revision.id, { code: value })}
          />
          <InputField
            label="Date"
            value={revision.date}
            onChange={(value) => updateRevision(revision.id, { date: value })}
          />
          <InputField
            label="Note"
            value={revision.description}
            onChange={(value) => updateRevision(revision.id, { description: value })}
          />
          <button className={styles.deleteBtn} onClick={() => removeRevision(revision.id)}>
            Delete revision
          </button>
        </div>
      ))}
    </div>
  );
}

function SheetViewportProperties({ sheet, viewport, project, dispatch, u }) {
  const sheetScene = buildSheetScene(project, sheet);
  const sceneViewport = sheetScene?.viewports.find((entry) => entry.id === viewport.id) || null;
  const displayedViewport = sceneViewport || viewport;

  const updateViewport = (updates) => {
    const isManualEdit = ['x', 'y', 'width', 'height', 'rotation'].some((key) => key in updates);
    const baseViewport = sceneViewport
      ? {
          ...viewport,
          x: sceneViewport.x,
          y: sceneViewport.y,
          width: sceneViewport.width,
          height: sceneViewport.height,
          rotation: sceneViewport.rotation,
        }
      : viewport;
    const nextViewport = fitViewportToSheet({
      ...baseViewport,
      ...updates,
      lockAutoLayout: 'lockAutoLayout' in updates
        ? updates.lockAutoLayout
        : (isManualEdit ? true : baseViewport.lockAutoLayout),
    }, sheet);
    dispatch({ type: 'SHEET_VIEWPORT_UPDATE', sheetId: sheet.id, viewport: nextViewport });
  };

  const floorOptions = getOrderedFloors(project);
  const updateSource = (nextSourceView, nextFloorId = viewport.sourceFloorId, nextRefId) => {
    const floor = floorOptions.find((entry) => entry.id === nextFloorId) || null;
    const refId = nextRefId !== undefined
      ? nextRefId
      : nextSourceView === 'section' ? (floor?.sectionCuts || [])[0]?.id || null : null;
    updateViewport({
      sourceView: nextSourceView,
      sourceFloorId: nextFloorId,
      sourceRefId: refId,
      role: nextSourceView === '3d_preview'
        ? 'supplemental'
        : (viewport.role === 'supplemental' ? 'secondary' : viewport.role),
    });
  };

  const currentFloor = floorOptions.find((entry) => entry.id === viewport.sourceFloorId) || null;
  const sectionCutOptions = currentFloor?.sectionCuts || [];

  const source = resolveSheetViewportSource(project, viewport);

  const toggleLayoutMode = () => {
    if (sheet.layoutTemplate !== 'auto') return;
    if (viewport.lockAutoLayout) {
      updateViewport({ lockAutoLayout: false });
      return;
    }
    updateViewport({
      x: displayedViewport.x,
      y: displayedViewport.y,
      width: displayedViewport.width,
      height: displayedViewport.height,
      rotation: displayedViewport.rotation || 0,
      lockAutoLayout: true,
    });
  };

  return (
    <div>
      <div className={styles.title}>Sheet Viewport</div>
      <InputField label="Title" value={viewport.title} onChange={(value) => updateViewport({ title: value })} />
      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
        <label style={{ flex: '0 0 80px', fontSize: '12px', color: 'var(--color-text-secondary)' }}>Source</label>
        <select
          value={viewport.sourceView}
          onChange={(e) => updateSource(e.target.value)}
          style={{ flex: 1, height: '28px', padding: '0 4px', border: '1px solid var(--color-border)', borderRadius: 'var(--radius-sm)', fontSize: '12px' }}
        >
          <option value="plan">Plan</option>
          <option value="3d_preview">3D Preview</option>
          <option value="section">Section</option>
          <option value="elevation_front">Front Elevation</option>
          <option value="elevation_rear">Rear Elevation</option>
          <option value="elevation_left">Left Elevation</option>
          <option value="elevation_right">Right Elevation</option>
        </select>
      </div>
      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
        <label style={{ flex: '0 0 80px', fontSize: '12px', color: 'var(--color-text-secondary)' }}>Floor</label>
        <select
          value={viewport.sourceFloorId || ''}
          onChange={(e) => updateSource(viewport.sourceView, e.target.value)}
          style={{ flex: 1, height: '28px', padding: '0 4px', border: '1px solid var(--color-border)', borderRadius: 'var(--radius-sm)', fontSize: '12px' }}
        >
          {floorOptions.map((floor) => (
            <option key={floor.id} value={floor.id}>{floor.name}</option>
          ))}
        </select>
      </div>
      {viewport.sourceView === 'section' && sectionCutOptions.length > 0 && (
        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
          <label style={{ flex: '0 0 80px', fontSize: '12px', color: 'var(--color-text-secondary)' }}>Section Cut</label>
          <select
            value={viewport.sourceRefId || ''}
            onChange={(e) => updateSource('section', viewport.sourceFloorId, e.target.value || null)}
            style={{ flex: 1, height: '28px', padding: '0 4px', border: '1px solid var(--color-border)', borderRadius: 'var(--radius-sm)', fontSize: '12px' }}
          >
            {sectionCutOptions.map((sc) => (
              <option key={sc.id} value={sc.id}>{sc.label || sc.id}</option>
            ))}
          </select>
        </div>
      )}
      <InputField label="Source Label" value={source.title || getViewportSourceLabel(viewport.sourceView)} readOnly />
      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
        <label style={{ flex: '0 0 80px', fontSize: '12px', color: 'var(--color-text-secondary)' }}>Role</label>
        <select
          value={viewport.role}
          onChange={(e) => updateViewport({ role: e.target.value })}
          style={{ flex: 1, height: '28px', padding: '0 4px', border: '1px solid var(--color-border)', borderRadius: 'var(--radius-sm)', fontSize: '12px' }}
        >
          <option value="primary">Primary</option>
          <option value="secondary">Secondary</option>
          <option value="detail">Detail</option>
          <option value="supplemental">Supplemental</option>
        </select>
      </div>
      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
        <label style={{ flex: '0 0 80px', fontSize: '12px', color: 'var(--color-text-secondary)' }}>Caption</label>
        <select
          value={viewport.captionPosition}
          onChange={(e) => updateViewport({ captionPosition: e.target.value })}
          style={{ flex: 1, height: '28px', padding: '0 4px', border: '1px solid var(--color-border)', borderRadius: 'var(--radius-sm)', fontSize: '12px' }}
        >
          <option value="below">Below</option>
          <option value="above">Above</option>
        </select>
      </div>
      <InputField label="Reference" value={viewport.referenceNote || ''} onChange={(value) => updateViewport({ referenceNote: value })} />
      <InputField
        label="Frame Mode"
        value={sheet.layoutTemplate === 'auto' ? (viewport.lockAutoLayout ? 'Manual' : 'Auto') : 'Manual (sheet)'}
        readOnly
      />
      {sheet.layoutTemplate === 'auto' && (
        <button className={styles.actionBtn} onClick={toggleLayoutMode}>
          {viewport.lockAutoLayout ? 'Use auto layout' : 'Convert to manual frame'}
        </button>
      )}
      <div className={styles.subtitle}>Frame</div>
      <InputField label="X" type="number" suffix={u.suffix} value={u.toDisplay(displayedViewport.x)} onChange={(value) => updateViewport({ x: u.fromDisplay(value) })} />
      <InputField label="Y" type="number" suffix={u.suffix} value={u.toDisplay(displayedViewport.y)} onChange={(value) => updateViewport({ y: u.fromDisplay(value) })} />
      <InputField label="Width" type="number" suffix={u.suffix} value={u.toDisplay(displayedViewport.width)} onChange={(value) => updateViewport({ width: Math.max(20, u.fromDisplay(value)) })} />
      <InputField label="Height" type="number" suffix={u.suffix} value={u.toDisplay(displayedViewport.height)} onChange={(value) => updateViewport({ height: Math.max(20, u.fromDisplay(value)) })} />
      <InputField label="Scale 1:" type="number" value={Math.round(viewport.scale)} onChange={(value) => updateViewport({ scale: Math.max(1, Math.round(value)) })} />
      <InputField label="Rotation" type="number" suffix="°" step={1} value={displayedViewport.rotation || 0} onChange={(value) => updateViewport({ rotation: ((value % 360) + 360) % 360 })} />
    </div>
  );
}

function FloorProperties({ floor, dispatch, onDuplicate, onDelete, canDelete, u }) {
  const updateFloor = (updates) => {
    dispatch({ type: 'FLOOR_UPDATE', floor: { id: floor.id, ...updates } });
  };

  return (
    <div>
      <div className={styles.title}>Floor</div>
      <InputField
        label="Name"
        value={floor.name}
        onChange={(value) => updateFloor({ name: value })}
      />
      <InputField
        label="Level Index"
        type="number"
        step={1}
        value={getFloorLevelIndex(floor)}
        onChange={(value) => updateFloor({ levelIndex: Math.round(value) })}
      />
      <InputField
        label="Elevation"
        type="number"
        suffix={u.suffix}
        step={u.step(100)}
        value={u.toDisplay(getFloorElevation(floor))}
        onChange={(value) => updateFloor({ elevation: u.fromDisplay(value) })}
      />
      <InputField
        label="Floor to Floor"
        type="number"
        suffix={u.suffix}
        step={u.step(100)}
        value={u.toDisplay(getFloorToFloorHeight(floor))}
        onChange={(value) => updateFloor({ floorToFloorHeight: Math.max(100, u.fromDisplay(value)) })}
      />
      <div className={styles.subtitle}>Contents</div>
      <InputField label="Walls" value={floor.walls.length} readOnly />
      <InputField label="Rooms" value={floor.rooms.length} readOnly />
      <InputField label="Doors" value={floor.doors.length} readOnly />
      <InputField label="Windows" value={floor.windows.length} readOnly />
      <InputField label="Columns" value={(floor.columns || []).length} readOnly />
      <InputField label="Beams" value={(floor.beams || []).length} readOnly />
      <InputField label="Stairs" value={(floor.stairs || []).length} readOnly />
      <InputField label="Slabs" value={(floor.slabs || []).length} readOnly />
      <button
        className={styles.actionBtn}
        onClick={() => onDuplicate(floor)}
      >
        Duplicate floor
      </button>
      <button
        className={styles.deleteBtn}
        onClick={() => onDelete(floor)}
        disabled={!canDelete}
      >
        Delete floor
      </button>
    </div>
  );
}

function ProjectSummary({ project, floor, dispatch }) {
  return (
    <div>
      <div className={styles.title}>Project Summary</div>
      <InputField
        label="Name"
        value={project.name}
        onChange={(value) => dispatch({ type: 'PROJECT_SET_NAME', name: value })}
      />
      <InputField
        label="Address"
        value={project.address || ''}
        onChange={(value) => dispatch({ type: 'PROJECT_UPDATE', updates: { address: value } })}
      />
      <InputField
        label="Drawn By"
        value={project.documentDefaults?.drawnBy || ''}
        onChange={(value) => dispatch({
          type: 'PROJECT_UPDATE',
          updates: {
            documentDefaults: {
              ...(project.documentDefaults || {}),
              drawnBy: value,
            },
          },
        })}
      />
      <InputField
        label="Checked"
        value={project.documentDefaults?.checkedBy || ''}
        onChange={(value) => dispatch({
          type: 'PROJECT_UPDATE',
          updates: {
            documentDefaults: {
              ...(project.documentDefaults || {}),
              checkedBy: value,
            },
          },
        })}
      />
      <div className={styles.summary}>
        <p>Name: {project.name}</p>
        <p>Floors: {project.floors.length}</p>
        <p>Sheets: {(project.sheets || []).length}</p>
        {floor && (
          <>
            <p>Slabs: {(floor.slabs || []).length}</p>
            <p>Walls: {floor.walls.length}</p>
            <p>Annotations: {(floor.annotations || []).length}</p>
            <p>Beams: {(floor.beams || []).length}</p>
            <p>Stairs: {(floor.stairs || []).length}</p>
            <p>Section Cuts: {(floor.sectionCuts || []).length}</p>
            <p>Doors: {floor.doors.length}</p>
            <p>Windows: {floor.windows.length}</p>
            <p>Columns: {(floor.columns || []).length}</p>
          </>
        )}
      </div>
      {floor && <AnnotationSettingsProperties floor={floor} dispatch={dispatch} />}
    </div>
  );
}

export default function PropertiesPanel() {
  const { project, dispatch, duplicateFloor } = useProject();
  const { selectedId, selectedType, activeFloorId, activeSheetId, workspaceMode, dispatch: editorDispatch } = useEditor();
  const orderedFloors = getOrderedFloors(project);
  const floor = orderedFloors.find((entry) => entry.id === activeFloorId) || null;
  const sheet = (project.sheets || []).find((entry) => entry.id === activeSheetId) || null;
  const u = useUnits();

  const selectFloor = (floorId) => {
    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
    editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId });
    editorDispatch({ type: 'SELECT_OBJECT', id: floorId, objectType: 'floor' });
  };

  const handleDuplicateFloor = (floorToDuplicate) => {
    const duplicatedFloor = duplicateFloor(floorToDuplicate.id);
    if (!duplicatedFloor) return;

    dispatch({ type: 'FLOOR_DUPLICATE', floor: duplicatedFloor });
    selectFloor(duplicatedFloor.id);
  };

  const handleDeleteFloor = (floorToDelete) => {
    if (orderedFloors.length <= 1) return;
    const confirmed = window.confirm(`Delete "${floorToDelete.name}"?`);
    if (!confirmed) return;

    const remainingFloors = orderedFloors.filter((entry) => entry.id !== floorToDelete.id);
    const fallbackFloor = remainingFloors[0] || null;

    dispatch({
      type: 'FLOOR_DELETE',
      floorId: floorToDelete.id,
      fallbackFloorId: fallbackFloor?.id ?? null,
    });

    if (fallbackFloor) {
      selectFloor(fallbackFloor.id);
    } else {
      editorDispatch({ type: 'DESELECT' });
    }
  };

  const handleDelete = () => {
    if (!selectedId) return;
    if (selectedType === 'sheet') {
      dispatch({ type: 'SHEET_DELETE', sheetId: selectedId });
    } else if (selectedType === 'sheetViewport' && sheet) {
      dispatch({ type: 'SHEET_VIEWPORT_DELETE', sheetId: sheet.id, viewportId: selectedId });
    } else if (selectedType === 'slab') {
      dispatch({ type: 'SLAB_DELETE', floorId: activeFloorId, slabId: selectedId });
    } else if (selectedType === 'wall') {
      dispatch({ type: 'WALL_DELETE', floorId: activeFloorId, wallId: selectedId });
    } else if (selectedType === 'beam') {
      dispatch({ type: 'BEAM_DELETE', floorId: activeFloorId, beamId: selectedId });
    } else if (selectedType === 'sectionCut') {
      dispatch({ type: 'SECTION_DELETE', floorId: activeFloorId, sectionId: selectedId });
    } else if (selectedType === 'annotation') {
      dispatch({ type: 'ANNOTATION_DELETE', floorId: activeFloorId, annotationId: selectedId });
    } else if (selectedType === 'stair') {
      dispatch({ type: 'STAIR_DELETE', floorId: activeFloorId, stairId: selectedId });
    } else if (selectedType === 'landing') {
      dispatch({ type: 'LANDING_DELETE', floorId: activeFloorId, landingId: selectedId });
    } else if (selectedType === 'door') {
      dispatch({ type: 'DOOR_DELETE', floorId: activeFloorId, doorId: selectedId });
    } else if (selectedType === 'window') {
      dispatch({ type: 'WINDOW_DELETE', floorId: activeFloorId, windowId: selectedId });
    } else if (selectedType === 'column') {
      dispatch({ type: 'COLUMN_DELETE', floorId: activeFloorId, columnId: selectedId });
    } else if (selectedType === 'fixture') {
      dispatch({ type: 'FIXTURE_DELETE', floorId: activeFloorId, fixtureId: selectedId });
    } else if (selectedType === 'room') {
      dispatch({ type: 'ROOM_DELETE', floorId: activeFloorId, roomId: selectedId });
    } else if (selectedType === 'floor') {
      const targetFloor = orderedFloors.find((entry) => entry.id === selectedId) || null;
      if (targetFloor) {
        handleDeleteFloor(targetFloor);
        return;
      }
    }
    editorDispatch({ type: 'DESELECT' });
  };

  let content = workspaceMode === 'sheet' && sheet
    ? <SheetProperties sheet={sheet} project={project} dispatch={dispatch} editorDispatch={editorDispatch} activeFloorId={activeFloorId} u={u} />
    : (
        <>
          {floor && (
            <FloorProperties
              floor={floor}
              dispatch={dispatch}
              onDuplicate={handleDuplicateFloor}
              onDelete={handleDeleteFloor}
              canDelete={orderedFloors.length > 1}
              u={u}
            />
          )}
          <ProjectSummary project={project} floor={floor} dispatch={dispatch} />
        </>
      );

  if (selectedId && workspaceMode === 'sheet' && sheet) {
    if (selectedType === 'sheet') {
      if (sheet.id === selectedId) {
        content = <SheetProperties sheet={sheet} project={project} dispatch={dispatch} editorDispatch={editorDispatch} activeFloorId={activeFloorId} u={u} />;
      }
    } else if (selectedType === 'sheetViewport') {
      const viewport = (sheet.viewports || []).find((entry) => entry.id === selectedId);
      if (viewport) {
        content = <SheetViewportProperties sheet={sheet} viewport={viewport} project={project} dispatch={dispatch} u={u} />;
      }
    }
  } else if (selectedId && floor) {
    if (selectedType === 'floor') {
      const selectedFloor = orderedFloors.find((entry) => entry.id === selectedId) || floor;
      content = (
        <FloorProperties
          floor={selectedFloor}
          dispatch={dispatch}
          onDuplicate={handleDuplicateFloor}
          onDelete={handleDeleteFloor}
          canDelete={orderedFloors.length > 1}
          u={u}
        />
      );
    } else if (selectedType === 'slab') {
      const slab = (floor.slabs || []).find(s => s.id === selectedId) || null;
      if (slab) {
        content = <SlabProperties slab={slab} floor={floor} dispatch={dispatch} floorId={activeFloorId} u={u} />;
      }
    } else if (selectedType === 'wall') {
      const wall = floor.walls.find(w => w.id === selectedId);
      if (wall) {
        content = <WallProperties wall={wall} dispatch={dispatch} floorId={activeFloorId} u={u} />;
      }
    } else if (selectedType === 'beam') {
      const beam = (floor.beams || []).find(b => b.id === selectedId);
      if (beam) {
        content = <BeamProperties beam={beam} floor={floor} dispatch={dispatch} floorId={activeFloorId} u={u} />;
      }
    } else if (selectedType === 'sectionCut') {
      const sectionCut = (floor.sectionCuts || []).find(s => s.id === selectedId) || null;
      if (sectionCut) {
        content = <SectionCutProperties sectionCut={sectionCut} dispatch={dispatch} floorId={activeFloorId} editorDispatch={editorDispatch} u={u} />;
      }
    } else if (selectedType === 'annotation') {
      const annotation = (floor.annotations || []).find((entry) => entry.id === selectedId);
      if (annotation) {
        content = <AnnotationProperties annotation={annotation} floor={floor} dispatch={dispatch} floorId={activeFloorId} u={u} />;
      }
    } else if (selectedType === 'stair') {
      const stair = (floor.stairs || []).find(entry => entry.id === selectedId);
      if (stair) {
        content = <StairProperties stair={stair} project={project} dispatch={dispatch} floorId={activeFloorId} u={u} />;
      }
    } else if (selectedType === 'landing') {
      const landing = (floor.landings || []).find(l => l.id === selectedId);
      if (landing) {
        content = <LandingProperties landing={landing} floor={floor} dispatch={dispatch} floorId={activeFloorId} u={u} />;
      }
    } else if (selectedType === 'door') {
      const door = floor.doors.find(d => d.id === selectedId);
      const wall = door ? floor.walls.find(w => w.id === door.wallId) : null;
      if (door) {
        content = <DoorProperties door={door} wall={wall} dispatch={dispatch} floorId={activeFloorId} editorDispatch={editorDispatch} u={u} />;
      }
    } else if (selectedType === 'window') {
      const win = floor.windows.find(w => w.id === selectedId);
      const wall = win ? floor.walls.find(w => w.id === win.wallId) : null;
      if (win) {
        content = <WindowProperties window={win} wall={wall} dispatch={dispatch} floorId={activeFloorId} u={u} />;
      }
    } else if (selectedType === 'column') {
      const column = (floor.columns || []).find(c => c.id === selectedId);
      if (column) {
        content = <ColumnProperties column={column} floor={floor} dispatch={dispatch} floorId={activeFloorId} editorDispatch={editorDispatch} u={u} />;
      }
    } else if (selectedType === 'fixture') {
      const fixture = (floor.fixtures || []).find(f => f.id === selectedId);
      if (fixture) {
        content = <FixtureProperties fixture={fixture} dispatch={dispatch} floorId={activeFloorId} u={u} />;
      }
    } else if (selectedType === 'room') {
      const room = floor.rooms.find(r => r.id === selectedId);
      if (room) {
        content = <RoomProperties room={room} dispatch={dispatch} floorId={activeFloorId} />;
      }
    }
  }

  return (
    <div className={styles.panel}>
      <div className={styles.segmentControl}>
        <button
          className={u.unit === 'mm' ? styles.segmentBtnActive : styles.segmentBtn}
          onClick={() => u.setUnit('mm')}
        >mm</button>
        <button
          className={u.unit === 'm' ? styles.segmentBtnActive : styles.segmentBtn}
          onClick={() => u.setUnit('m')}
        >m</button>
      </div>
      {workspaceMode === 'sheet' && sheet && (
        <SheetExportMenu sheet={sheet} editorDispatch={editorDispatch} />
      )}
      {content}
      {selectedId && selectedType !== 'floor' && (
        <button className={styles.deleteBtn} onClick={handleDelete}>
          Delete {selectedType === 'sheetViewport' ? 'viewport' : selectedType}
        </button>
      )}
    </div>
  );
}

