function WallDrawingProperties({ toolState, dispatch, editorDispatch, floorId, u }) {
  const start = toolState.start;
  const preview = toolState.preview;

  const currentLen = preview ? distance(start, preview) : 0;
  const angle = preview ? Math.atan2(preview.y - start.y, preview.x - start.x) : 0;

  const handleLengthSubmit = (newLen) => {
    if (!newLen || newLen <= 0 || !start) return;
    const lenMm = u.fromDisplay(newLen);
    const endPt = {
      x: start.x + Math.cos(angle) * lenMm,
      y: start.y + Math.sin(angle) * lenMm,
    };

    const wall = createWall(start, endPt, undefined, {
      startAttachment: toolState.startAttachment || null,
      endAttachment: null,
    });
    dispatch({ type: 'WALL_ADD', floorId, wall });

    // Chain: end becomes new start
    editorDispatch({
      type: 'UPDATE_TOOL_STATE',
      payload: { start: endPt, startAttachment: null, preview: null },
    });
  };

  return (
    <div>
      <div className={styles.title}>Drawing Wall</div>
      <InputField
        label="Start X" type="number" suffix={u.suffix}
        value={u.toDisplay(start.x)}
        readOnly
      />
      <InputField
        label="Start Y" type="number" suffix={u.suffix}
        value={u.toDisplay(start.y)}
        readOnly
      />
      <InputField
        label="Length" type="number" suffix={u.suffix} step={u.step(100)}
        value={currentLen > 0 ? u.toDisplay(currentLen) : ''}
        onChange={handleLengthSubmit}
      />
      {preview && (
        <InputField
          label="Angle" type="number" suffix="°"
          value={Math.round((angle * 180) / Math.PI)}
          readOnly
        />
      )}
    </div>
  );
}

