        onChange={(v) => updateBeam({ floorLevel: u.fromDisplay(v) })}
      />
      <InputField
        label="Span" type="number" suffix={u.suffix}
        value={u.toDisplay(len)}
        readOnly
      />
    </div>
  );
}

