function WallDrawingProperties({ toolState, dispatch, editorDispatch, floorId, u }) {
  const start = toolState.start;
  const preview = toolState.preview;
  const lengthRef = useRef(null);
  const angleRef = useRef(null);

  const currentLen = preview ? distance(start, preview) : 0;
  const currentAngle = preview ? Math.atan2(preview.y - start.y, preview.x - start.x) : 0;

  const commitWall = (lenMm, angleDeg) => {
    if (!lenMm || lenMm <= 0 || !start) return;
    const angleRad = (angleDeg * Math.PI) / 180;
    const endPt = {
      x: start.x + Math.cos(angleRad) * lenMm,
      y: start.y + Math.sin(angleRad) * lenMm,
    };

    const wall = createWall(start, endPt, undefined, {
      startAttachment: toolState.startAttachment || null,
      endAttachment: null,
    });
    dispatch({ type: 'WALL_ADD', floorId, wall });

    // Chain: end becomes new start
    editorDispatch({
      type: 'UPDATE_TOOL_STATE',
      payload: { start: endPt, startAttachment: null, preview: null },
    });
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      const lenVal = parseFloat(lengthRef.current?.value);
      const angVal = parseFloat(angleRef.current?.value);
      if (isNaN(lenVal) || lenVal <= 0) return;
      const angleDeg = isNaN(angVal) ? Math.round((currentAngle * 180) / Math.PI) : angVal;
      commitWall(u.fromDisplay(lenVal), angleDeg);
    }
  };

  return (
    <div>
      <div className={styles.title}>Drawing Wall</div>
      <InputField
        label="Start X" type="number" suffix={u.suffix}
        value={u.toDisplay(start.x)}
        readOnly
      />
      <InputField
        label="Start Y" type="number" suffix={u.suffix}
        value={u.toDisplay(start.y)}
        readOnly
      />
      <div className={inputStyles.field}>
        <label className={inputStyles.label}>Length</label>
        <div className={inputStyles.inputWrap}>
          <input
            ref={lengthRef}
            type="number"
            className={[inputStyles.input, inputStyles.inputNumber].join(' ')}
            placeholder={currentLen > 0 ? String(u.toDisplay(currentLen)) : ''}
            step={u.step(100)}
            onKeyDown={handleKeyDown}
          />
          <span className={inputStyles.suffix}>{u.suffix}</span>
        </div>
      </div>
      <div className={inputStyles.field}>
        <label className={inputStyles.label}>Angle</label>
        <div className={inputStyles.inputWrap}>
          <input
            ref={angleRef}
            type="number"

