  5→export function wallOutline(wall) {
  6→  const dir = normalize(subtract(wall.end, wall.start));
  7→  const perp = perpendicular(dir);
  8→  const halfThick = wall.thickness / 2;
  9→  const offset = scale(perp, halfThick);
 10→
 11→  return [
 12→    add(wall.start, offset),
 13→    add(wall.end, offset),
 14→    subtract(wall.end, offset),
 15→    subtract(wall.start, offset),
 16→  ];
 17→}
 18→
 19→export function wallLength(wall) {
 20→  return segmentLength(wall.start, wall.end);
 21→}
 22→
 23→export function resizeWallFromStart(wall, requestedLength, minLength = MIN_WALL_LENGTH) {
 24→  const targetLength = Math.max(minLength, Number(requestedLength) || 0);
 25→  const direction = normalize(subtract(wall.end, wall.start));
 26→  const safeDirection = (direction.x === 0 && direction.y === 0)
 27→    ? { x: 1, y: 0 }
 28→    : direction;
 29→
 30→  return {
 31→    start: wall.start,
 32→    end: add(wall.start, scale(safeDirection, targetLength)),
 33→  };
 34→}
 35→
 36→export function clampWallOpeningOffset(length, width, offset) {
 37→  const safeLength = Math.max(0, Number(length) || 0);
 38→  const safeWidth = Math.max(0, Number(width) || 0);
 39→  const safeOffset = Number(offset) || 0;
 40→  const halfWidth = safeWidth / 2;
 41→
 42→  if (safeLength <= 0) return 0;
 43→  if (safeWidth >= safeLength) return safeLength / 2;
 44→
 45→  return Math.max(halfWidth, Math.min(safeLength - halfWidth, safeOffset));
 46→}
 47→
 48→export function positionOnWall(wall, offset) {
 49→  const dir = normalize(subtract(wall.end, wall.start));
 50→  return add(wall.start, scale(dir, offset));
 51→}
 52→
 53→export function wallDirection(wall) {
 54→  return normalize(subtract(wall.end, wall.start));
 55→}
 56→
 57→export function wallAngle(wall) {
 58→  const dx = wall.end.x - wall.start.x;
 59→  const dy = wall.end.y - wall.start.y;
 60→  return Math.atan2(dy, dx);
 61→}
 62→
 63→export function projectPointOnWall(wall, point) {
 64→  const dir = subtract(wall.end, wall.start);
 65→  const len = segmentLength(wall.start, wall.end);
 66→  if (len === 0) return 0;
 67→  const toPoint = subtract(point, wall.start);
 68→  const t = dot(toPoint, dir) / (len * len);
 69→  return Math.max(0, Math.min(len, t * len));
 70→}
