 72→export function doorOutlineOnWall(wall, door) {
 73→  const dir = wallDirection(wall);
 74→  const perp = perpendicular(dir);
 75→  const halfThick = wall.thickness / 2;
 76→  const halfWidth = door.width / 2;
 77→
 78→  const center = positionOnWall(wall, door.offset);
 79→  const start = add(center, scale(dir, -halfWidth));
 80→  const end = add(center, scale(dir, halfWidth));
 81→
 82→  return {
 83→    center,
 84→    start,
 85→    end,
 86→    p1: add(start, scale(perp, halfThick)),
 87→    p2: add(end, scale(perp, halfThick)),
 88→    p3: subtract(end, scale(perp, halfThick)),
 89→    p4: subtract(start, scale(perp, halfThick)),
 90→    angle: wallAngle(wall),
 91→    width: door.width,
 92→    openDirection: door.openDirection,
 93→  };
 94→}
