  5→
  6→function constrainAngle(start, end, shiftHeld) {
  7→  if (!shiftHeld) return end;
  8→  const dx = end.x - start.x;
  9→  const dy = end.y - start.y;
 10→  const angle = Math.atan2(dy, dx);
 11→  const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
 12→  const len = Math.sqrt(dx * dx + dy * dy);
 13→  return {
 14→    x: start.x + Math.cos(snapAngle) * len,
 15→    y: start.y + Math.sin(snapAngle) * len,
 16→  };
 17→}
 18→
 19→export function createWallDrawHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport, snapEnabled }) {
 20→  return {
 21→    onMouseDown(modelPos, e, toolState) {
 22→      if (e.button !== 0) return;
 23→
 24→      const floor = getFloor(activeFloorId);
 25→      if (!floor) return;
 26→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
 27→      const shiftHeld = e.shiftKey;
 28→
 29→      let snapped = modelPos;
 30→      let attachment = null;
 31→      if (snapEnabled) {
 32→        const snapResult = snapWallEndpoint(modelPos, {
 33→          walls: floor.walls,
 34→          columns: floor.columns || [],
 35→          snapDist: snapDistModel,
 36→          chainStart: toolState.chainStart,
 37→          otherPoint: toolState.start,
 38→        });
 39→        if (snapResult) {
 40→          snapped = { ...snapResult.point };
 41→          attachment = snapResult.attachment;
 42→        }
 43→      }
 44→      if (shiftHeld && toolState.start) {
 45→        snapped = constrainAngle(toolState.start, snapped, true);
 46→        attachment = null;
 47→      }
 48→
 49→      if (!toolState.start) {
 50→        // First click: set start
 51→        editorDispatch({
 52→          type: 'UPDATE_TOOL_STATE',
 53→          payload: { start: snapped, chainStart: snapped, startAttachment: attachment, preview: null },
 54→        });
 55→      } else {
 56→        // Second+ click: create wall and chain
 57→        const endPt = snapped;
 58→
 59→        const len = distance(toolState.start, endPt);
 60→        if (len < MIN_WALL_LENGTH) return;
 61→
 62→        const wall = createWall(toolState.start, endPt, undefined, {
 63→          startAttachment: toolState.startAttachment || null,
 64→          endAttachment: attachment,
 65→        });
 66→        dispatch({ type: 'WALL_ADD', floorId: activeFloorId, wall });
 67→
 68→        // Check if we snapped back to chain start (close loop)
 69→        if (toolState.chainStart && distance(endPt, toolState.chainStart) < snapDistModel) {
 70→          editorDispatch({
 71→            type: 'UPDATE_TOOL_STATE',
 72→            payload: { start: null, chainStart: null, startAttachment: null, preview: null },
 73→          });
 74→        } else {
 75→          // Chain: end becomes new start
 76→          editorDispatch({
 77→            type: 'UPDATE_TOOL_STATE',
 78→            payload: { start: endPt, startAttachment: attachment, preview: null },
 79→          });
 80→        }
 81→      }
 82→    },
 83→
 84→    onMouseMove(modelPos, e, toolState) {
 85→      if (!toolState.start) return;
 86→      let preview = modelPos;
 87→
 88→      const floor = getFloor(activeFloorId);
 89→      if (!floor) return;
 90→      const snapDistModel = SNAP_DISTANCE_PX / viewport.zoom;
 91→      if (snapEnabled) {
 92→        const snapResult = snapWallEndpoint(modelPos, {
 93→          walls: floor.walls,
 94→          columns: floor.columns || [],
 95→          snapDist: snapDistModel,
 96→          chainStart: toolState.chainStart,
 97→          otherPoint: toolState.start,
 98→        });
 99→        if (snapResult) preview = { ...snapResult.point };
100→      }
101→      if (e.shiftKey) {
102→        preview = constrainAngle(toolState.start, preview, true);
103→      }
104→
105→      editorDispatch({
106→        type: 'UPDATE_TOOL_STATE',
107→        payload: { preview },
108→      });
109→    },
110→
111→    onDoubleClick(modelPos, e, toolState) {
112→      // Finish chain
113→      editorDispatch({
114→        type: 'UPDATE_TOOL_STATE',
115→        payload: { start: null, chainStart: null, startAttachment: null, preview: null },
116→      });
117→    },
118→
119→    onKeyDown(e, toolState) {
120→      if (e.key === 'Escape') {
121→        editorDispatch({
122→          type: 'UPDATE_TOOL_STATE',
123→          payload: { start: null, chainStart: null, startAttachment: null, preview: null },
124→        });
125→      }
126→    },
127→
128→    getCursor(toolState) {
129→      return 'crosshair';
130→    },
131→  };
132→}
