1406→    if (!confirmed) return;
1407→
1408→    const remainingFloors = orderedFloors.filter((entry) => entry.id !== floorToDelete.id);
1409→    const fallbackFloor = remainingFloors[0] || null;
1410→
1411→    dispatch({
