 23→export function resizeWallFromStart(wall, requestedLength, minLength = MIN_WALL_LENGTH) {
 24→  const targetLength = Math.max(minLength, Number(requestedLength) || 0);
 25→  const direction = normalize(subtract(wall.end, wall.start));
 26→  const safeDirection = (direction.x === 0 && direction.y === 0)
 27→    ? { x: 1, y: 0 }
 28→    : direction;
 29→
 30→  return {
 31→    start: wall.start,
 32→    end: add(wall.start, scale(safeDirection, targetLength)),
